#include <cstdint>
#include <cstdio>

int main() {
    uint64_t big = 5000000000ULL;
    if (big <= UINT32_MAX) {
        uint32_t small = static_cast<uint32_t>(big);
        std::printf("%u\n", small);
    }
    return 0;
}

