#include <cstdint>
#include <cstdio>

int main() {
    int64_t big = 3000000000LL;
    if (big >= INT32_MIN && big <= INT32_MAX) {
        int32_t small = static_cast<int32_t>(big);
        std::printf("%d\n", small);
    }
    return 0;
}

